}

func newUserPositionResponse(pos *dmarkets.UserPosition) userPositionResponse {
	if pos == nil {
		return userPositionResponse{}
	}

	return userPositionResponse{
		Username:         pos.Username,
		MarketID:         pos.MarketID,
		YesSharesOwned:   pos.YesSharesOwned,
		NoSharesOwned:    pos.NoSharesOwned,
		Value:            pos.Value,
		TotalSpent:       pos.TotalSpent,
		TotalSpentInPlay: pos.TotalSpentInPlay,
		IsResolved:       pos.IsResolved,
		ResolutionResult: pos.ResolutionResult,
	}
}

package handlers

import (
	"encoding/json"
	"net/http"
)

type FailureReason string

const (
	ReasonMethodNotAllowed FailureReason = "METHOD_NOT_ALLOWED"
	ReasonInvalidRequest   FailureReason = "INVALID_REQUEST"
	ReasonInvalidToken     FailureReason = "INVALID_TOKEN"

	ReasonValidationFailed FailureReason = "VALIDATION_FAILED"
	ReasonInternalError    FailureReason = "INTERNAL_ERROR"
)

type SuccessEnvelope[T any] struct {
	OK     bool `json:"ok"`
	Result T    `json:"result"`
}

type FailureEnvelope struct {
	OK     bool   `json:"ok"`
	Reason string `json:"reason"`
}

func WriteResult[T any](w http.ResponseWriter, statusCode int, result T) error {
	return writeJSON(w, statusCode, SuccessEnvelope[T]{
		OK:     true,
		Result: result,
	})
}

func WriteFailure(w http.ResponseWriter, statusCode int, reason FailureReason) error {
	return writeJSON(w, statusCode, FailureEnvelope{
		OK:     false,
		Reason: string(reason),
	})
}

func WriteBusinessFailure(w http.ResponseWriter, reason FailureReason) error {
	return WriteFailure(w, http.StatusOK, reason)
}

func writeJSON(w http.ResponseWriter, statusCode int, payload any) error {
	body, err := json.Marshal(payload)
	if err != nil {
		return err
	}

	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(statusCode)
	_, err = w.Write(append(body, '\n'))
	return err
}

package buybetshandlers

import (
	"encoding/json"
	"errors"
	"net/http"

	"socialpredict/handlers"
	"socialpredict/handlers/bets/dto"
	dbets "socialpredict/internal/domain/bets"
	dmarkets "socialpredict/internal/domain/markets"
	dusers "socialpredict/internal/domain/users"
	authsvc "socialpredict/internal/service/auth"
)

const (
	reasonBetValidationFailed  handlers.FailureReason = "BET_VALIDATION_FAILED"
	reasonMarketClosed         handlers.FailureReason = "MARKET_CLOSED"
	reasonInsufficientBalance  handlers.FailureReason = "INSUFFICIENT_BALANCE"
	reasonMarketNotFound       handlers.FailureReason = "MARKET_NOT_FOUND"
	reasonPasswordChangeNeeded handlers.FailureReason = "PASSWORD_CHANGE_REQUIRED"
)

// PlaceBetHandler returns an HTTP handler that delegates bet placement to the bets domain service.
func PlaceBetHandler(betsSvc dbets.ServiceInterface, usersSvc dusers.ServiceInterface) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodPost {
			_ = handlers.WriteFailure(w, http.StatusMethodNotAllowed, handlers.ReasonMethodNotAllowed)
			return
		}

		user, httpErr := authsvc.ValidateUserAndEnforcePasswordChangeGetUser(r, usersSvc)
		if httpErr != nil {
			_ = handlers.WriteFailure(w, httpErr.StatusCode, reasonFromAuthError(httpErr))
			return
		}

		req, decodeErr := decodePlaceBetRequest(r)
		if decodeErr != nil {
			_ = handlers.WriteFailure(w, http.StatusBadRequest, handlers.ReasonInvalidRequest)
			return
		}

		placedBet, err := betsSvc.Place(r.Context(), toPlaceRequest(req, user.Username))
		if err != nil {
			writePlaceBetError(w, err)
			return
		}

		writePlaceBetResponse(w, placedBet)
	}
}

func decodePlaceBetRequest(r *http.Request) (dto.PlaceBetRequest, error) {
	var req dto.PlaceBetRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		return dto.PlaceBetRequest{}, errors.New("Invalid request body")
	}
	return req, nil
}

func toPlaceRequest(req dto.PlaceBetRequest, username string) dbets.PlaceRequest {
	return dbets.PlaceRequest{
		Username: username,
		MarketID: req.MarketID,
		Amount:   req.Amount,
		Outcome:  req.Outcome,
	}
}

func writePlaceBetError(w http.ResponseWriter, err error) {
	switch err {
	case dbets.ErrInvalidOutcome, dbets.ErrInvalidAmount:
		_ = handlers.WriteFailure(w, http.StatusBadRequest, reasonBetValidationFailed)
	case dbets.ErrMarketClosed:
		_ = handlers.WriteFailure(w, http.StatusConflict, reasonMarketClosed)
	case dbets.ErrInsufficientBalance:
		_ = handlers.WriteFailure(w, http.StatusUnprocessableEntity, reasonInsufficientBalance)
	case dmarkets.ErrMarketNotFound:
		_ = handlers.WriteFailure(w, http.StatusNotFound, reasonMarketNotFound)
	default:
		_ = handlers.WriteFailure(w, http.StatusInternalServerError, handlers.ReasonInternalError)
	}
}

func writePlaceBetResponse(w http.ResponseWriter, placedBet *dbets.PlacedBet) {
	response := dto.PlaceBetResponse{
		Username: placedBet.Username,
		MarketID: placedBet.MarketID,
		Amount:   placedBet.Amount,
		Outcome:  placedBet.Outcome,
		PlacedAt: placedBet.PlacedAt,
	}

	_ = handlers.WriteResult(w, http.StatusCreated, response)
}

func reasonFromAuthError(err *authsvc.HTTPError) handlers.FailureReason {
	if err == nil {
		return handlers.ReasonInternalError
	}

	switch err.Message {
	case "Authorization header is required", "Invalid token":
		return handlers.ReasonInvalidToken
	case "Password change required":
		return reasonPasswordChangeNeeded
	default:
		if err.StatusCode >= http.StatusInternalServerError {
			return handlers.ReasonInternalError
		}
		return handlers.ReasonInvalidToken
	}
}

package http

import (
	"context"
	"encoding/json"
	"net/http"
	"socialpredict/handlers"
	"socialpredict/handlers/cms/homepage"
	authsvc "socialpredict/internal/service/auth"
)

const (
	reasonHomepageAuthUnavailable handlers.FailureReason = "AUTH_SERVICE_UNAVAILABLE"
	reasonHomepageAdminRequired   handlers.FailureReason = "ADMIN_REQUIRED"
	reasonHomepageUpdateFailed    handlers.FailureReason = "HOMEPAGE_UPDATE_FAILED"
)

type Handler struct {
	svc  *homepage.Service
	auth authsvc.Authenticator
}

func NewHandler(svc *homepage.Service, auth authsvc.Authenticator) *Handler {
	return &Handler{svc: svc, auth: auth}
}

func (h *Handler) PublicGet(w http.ResponseWriter, r *http.Request) {
	item, err := h.svc.GetHome()
	if err != nil {
		http.Error(w, "not found", http.StatusNotFound)
		return
	}

	w.Header().Set("Content-Type", "application/json")
	_ = json.NewEncoder(w).Encode(map[string]interface{}{
		"title":     item.Title,
		"format":    item.Format,
		"html":      item.HTML,
		"markdown":  item.Markdown, // optional to expose
		"version":   item.Version,
		"updatedAt": item.UpdatedAt,
	})
}

type updateReq struct {
	Title    string `json:"title"`
	Format   string `json:"format"`   // "markdown" | "html"
	Markdown string `json:"markdown"` // when format=markdown
	HTML     string `json:"html"`     // when format=html
	Version  uint   `json:"version"`
}

func (h *Handler) AdminUpdate(w http.ResponseWriter, r *http.Request) {
	// Validate admin access
	if h.auth == nil {
		_ = handlers.WriteFailure(w, http.StatusInternalServerError, reasonHomepageAuthUnavailable)
		return
	}
	admin, httpErr := h.auth.RequireAdmin(r)
	if httpErr != nil {
		_ = handlers.WriteFailure(w, httpErr.StatusCode, reasonFromAdminAuthError(httpErr))
		return
	}

	var in updateReq
	if err := json.NewDecoder(r.Body).Decode(&in); err != nil {
		_ = handlers.WriteFailure(w, http.StatusBadRequest, handlers.ReasonInvalidRequest)
		return
	}

	item, err := h.svc.UpdateHome(homepage.UpdateInput{
		Title:     in.Title,
		Format:    in.Format,
		Markdown:  in.Markdown,
		HTML:      in.HTML,
		Version:   in.Version,
		UpdatedBy: admin.Username,
	})
	if err != nil {
		_ = handlers.WriteFailure(w, http.StatusBadRequest, reasonHomepageUpdateFailed)
		return
	}

	_ = handlers.WriteResult(w, http.StatusOK, map[string]interface{}{
		"title":   item.Title,
		"format":  item.Format,
		"html":    item.HTML,
		"version": item.Version,
	})
}

// RequireAdmin middleware wrapper that can be used in routes when an authenticator is available.
func RequireAdmin(auth authsvc.Authenticator, next http.HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		if auth == nil {
			_ = handlers.WriteFailure(w, http.StatusInternalServerError, reasonHomepageAuthUnavailable)
			return
		}
		if _, httpErr := auth.RequireAdmin(r); httpErr != nil {
			_ = handlers.WriteFailure(w, httpErr.StatusCode, reasonFromAdminAuthError(httpErr))
			return
		}
		next.ServeHTTP(w, r)
	}
}

// UsernameFromContext extracts username from request context (helper function)
